// WRONG: multiple enumeration — 2 DB queries
var orders = db.Orders.Where(o => o.Status == "pending");
if (orders.Any())  // query 1
    var first = orders.First(); // query 2

// RIGHT: materialize 1 lần
var orders = await db.Orders.Where(o => o.Status == "pending").ToListAsync();
var first = orders.FirstOrDefault();

// WRONG: Count() > 0 — full COUNT(*) query
if (db.Orders.Count() > 0) { } // COUNT(*) toàn bộ bảng

// RIGHT: .Any() — SELECT 1 WHERE ... LIMIT 1
if (await db.Orders.AnyAsync()) { }

// WRONG: deferred execution leak — IQueryable ra khỏi repo
public IQueryable<Order> GetActive() =>   // caller có thể thêm filter nhưng cũng có thể
    db.Orders.Where(o => o.IsActive);     // materialize sau khi DbContext bị dispose

// RIGHT: materialize trong repo
public async Task<IReadOnlyList<Order>> GetActiveAsync(CancellationToken ct) =>
    await db.Orders.Where(o => o.IsActive).AsNoTracking().ToListAsync(ct);

